import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { CategoryInfo, DataService } from './data.service';

@Component({
  selector: 'app-test-results',
  templateUrl: './test-results.component.html',
  styleUrls: ['./test-results.component.css'],
})
export class TestResultsComponent implements OnInit {
  rules: string[] = [];
  categories: string[] = [];
  categoryInfo: Record<string, CategoryInfo> = {};
  loading = true;
  error = '';

  constructor(private route: ActivatedRoute, private router: Router, private dataService: DataService) {}

  ngOnInit(): void {
    this.route.queryParams.subscribe((params) => {
      this.rules = [];
      this.categories = [];
      if (params['regole']) {
        try {
          this.rules = JSON.parse(params['regole']);
        } catch {
          this.rules = [];
        }
      }
      if (params['categorie']) {
        try {
          this.categories = JSON.parse(params['categorie']);
        } catch {
          this.categories = [];
        }
      }
      this.loadCategories();
    });
  }

  loadCategories(): void {
    this.loading = true;
    this.dataService.loadData().subscribe({
      next: () => {
        this.categoryInfo = this.dataService.getAllCategories();
        this.loading = false;
      },
      error: () => {
        this.loading = false;
      },
    });
  }

  getCategoryName(id: string): string {
    return this.categoryInfo[id]?.nome || id;
  }

  goHome(): void {
    this.router.navigate(['/']);
  }
}
<nav class="navbar-custom d-flex align-items-center justify-content-between flex-wrap gap-2">
  <a class="navbar-brand-text text-decoration-none" routerLink="/">🌿 Educazione Digitale Familiare</a>
  <a class="btn-search" (click)="goHome()" style="cursor:pointer;text-decoration:none;font-size:0.9rem;">Torna alla home</a>
</nav>

<section class="results-shell">
  <div class="section-label">Patto Familiare</div>
  <h2 class="section-title">Regole consigliate per la tua famiglia</h2>
  <p class="section-sub">Ecco le regole emerse in base alle tue risposte. Puoi tornare indietro e modificare la valutazione quando vuoi.</p>

  <div *ngIf="loading" class="info-box">Caricamento risultati...</div>
  <div *ngIf="!loading && rules.length === 0" class="info-box info-box-error">Nessuna regola disponibile. Torna indietro e prova di nuovo.</div>

  <div *ngIf="!loading && rules.length" class="results-list">
    <div *ngIf="categories.length" class="categories-summary">
      <div class="section-label">Categorie usate</div>
      <p>{{ categories.map(getCategoryName).join(', ') }}</p>
    </div>

    <div class="rule-card" *ngFor="let rule of rules; index as i">
      <div class="rule-label">Regola {{ i + 1 }}</div>
      <p>{{ rule }}</p>
    </div>

    <div class="results-actions">
      <button class="btn-primary-hero" (click)="goHome()">Ricomincia la ricerca</button>
    </div>
  </div>
</section>
